import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Container, Card, Badge, Spinner, Alert } from 'react-bootstrap';
import './topics.css';
import { useParams } from 'react-router-dom';

const TutorialTopics = () => {
  const [topics, setTopics] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const { slug } = useParams();

  useEffect(() => {
    const fetchTopics = async () => {
      try {
        // Note: You'll need to replace ':slug' with an actual slug value
        const response = await axios.get(`https://codewithsathya.pythonanywhere.com/tutorials/${slug}/`);
        setTopics(response.data.topics || []);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchTopics();
  }, []);

  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'long', day: 'numeric' };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  if (loading) {
    return (
      <div className="app-container">
        <Container className="text-center py-5">
          <Spinner animation="border" variant="light" />
          <h5 className="mt-3 text-light">Loading Tutorials...</h5>
        </Container>
      </div>
    );
  }

  if (error) {
    return (
      <div className="app-container">
        <Container className="py-5">
          <Alert variant="danger">
            <Alert.Heading>Error Loading Data</Alert.Heading>
            <p>{error}</p>
          </Alert>
        </Container>
      </div>
    );
  }

  return (
    <div className="app-container">
      <Container className="py-4">
        <h1 className="text-center mb-4 text-light">Tutorial Topics</h1>

        {topics.length === 0 ? (
          <Alert variant="info" className="text-center">
            No topics found.
          </Alert>
        ) : (
          topics.map((topic) => (
            <Card key={topic.id} className="mb-4 topic-card">
              <Card.Body>
                <div className="d-flex justify-content-between align-items-center mb-3">
                  <Card.Title className="text-primary">{topic.title}</Card.Title>
                  {topic.is_free && (
                    <Badge bg="success" className="fs-6">
                      FREE
                    </Badge>
                  )}
                </div>

                <div className="mb-3">
                  {topic.tags.map((tag, index) => (
                    <Badge key={index} bg="secondary" className="me-2 tag-badge">
                      {tag}
                    </Badge>
                  ))}
                </div>

                <hr className="divider" />

                <div
                  className="content-html"
                  dangerouslySetInnerHTML={{ __html: topic.content }}
                />

                {topic.code_snippet && (
                  <pre className="code-snippet mt-3">
                    <code>{topic.code_snippet}</code>
                  </pre>
                )}

                {topic.video_url && (
                  <div className="mt-3">
                    <h6 className="text-muted">Video Tutorial:</h6>
                    <div className="ratio ratio-16x9">
                      <iframe
                        src={topic.video_url}
                        title={topic.title}
                        allowFullScreen
                      />
                    </div>
                  </div>
                )}

                <div className="d-flex justify-content-between mt-4 text-muted small">
                  <span>Created: {formatDate(topic.created_at)}</span>
                  <span>Updated: {formatDate(topic.updated_at)}</span>
                </div>
              </Card.Body>
            </Card>
          ))
        )}
      </Container>
    </div>
  );
};

export default TutorialTopics;
